const fs = require('fs');
const http = require('http');
const config = JSON.parse(fs.readFileSync('./server.json', 'utf8'));
console.log(`[Boot] Starting ${config.serverName}...`);
console.log(`[Boot] Game Protocol listening on port ${config.port}`);
console.log(`[RCON] RCON Core active on port ${config.rconPort}`);
console.log(`[MOTD] ${config.motd}`);

let players = ['Player_One', 'GamerX', 'EliteSniper'];
let uptime = 0;

setInterval(() => {
  uptime += 10;
  console.log(`[Status] Heartbeat: ${players.length}/${config.maxPlayers} players online | Uptime: ${uptime}s`);
}, 10000);

// Minimal RCON HTTP/WebSocket trigger bridge
const server = http.createServer((req, res) => {
  if (req.method === 'POST' && req.url === '/rcon') {
    let body = '';
    req.on('data', chunk => body += chunk);
    req.on('end', () => {
      try {
        const data = JSON.parse(body);
        if (data.password !== config.rconPassword) {
          res.writeHead(403, { 'Content-Type': 'application/json' });
          return res.end(JSON.stringify({ error: 'RCON Authentication Failed' }));
        }
        const cmd = (data.command || '').trim();
        console.log(`[RCON Command] Executing: ${cmd}`);
        let output = 'Command executed successfully.';
        if (cmd === 'status') {
          output = `Server: ${config.serverName}\nPlayers: ${players.join(', ')} (${players.length}/${config.maxPlayers})\nUptime: ${uptime}s`;
        } else if (cmd.startsWith('say ')) {
          const msg = cmd.slice(4);
          console.log(`[Broadcast] [Console]: ${msg}`);
          output = `Broadcasted: ${msg}`;
        } else if (cmd.startsWith('kick ')) {
          const target = cmd.slice(5).trim();
          players = players.filter(p => p.toLowerCase() !== target.toLowerCase());
          console.log(`[Moderation] Kicked player: ${target}`);
          output = `Kicked ${target} from the server.`;
        }
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ response: output }));
      } catch (err) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: err.message }));
      }
    });
  } else {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ server: config.serverName, motd: config.motd, players, maxPlayers: config.maxPlayers, uptime }));
  }
});

server.listen(config.rconPort, () => {
  console.log(`[Ready] Daemon initialized successfully.`);
});
